from typing import Any

# Whitelist approach — safe even when the upstream schema changes
_CUSTOMER_FIELDS = {"id", "name", "plan", "created_at", "status"}
_ADDRESS_FIELDS  = {"city", "country", "postal_code"}

def get_customer(customer_id: str) -> dict:
    raw = _fetch_customer(customer_id)   # may include SSN, DOB, card_last4, internal_notes
    result: dict[str, Any] = {
        k: v for k, v in raw.items() if k in _CUSTOMER_FIELDS
    }
    if "billing_address" in raw:
        result["billing_address"] = {
            k: v for k, v in raw["billing_address"].items()
            if k in _ADDRESS_FIELDS
        }
    return result

def _fetch_customer(customer_id: str) -> dict:
