MAX_ROWS    = 20
MAX_STR_LEN = 300
MAX_RESULT_CHARS = 4000

def search_products(query: str, limit: int = MAX_ROWS) -> dict:
    raw_results = _search_index(query, limit=min(limit, MAX_ROWS))
    total_found = len(raw_results)

    items = []
    for r in raw_results[:MAX_ROWS]:
        items.append({
            "id": r["id"],
            "name": r["name"][:MAX_STR_LEN],
            "price_usd": r["price"],
            "in_stock": r["stock"] > 0,
            # Omit: raw_description (can be 10k chars), internal_sku, warehouse_id
        })

    result = {
        "query": query,
        "total_found": total_found,
        "returned": len(items),
        "items": items,
    }
    if total_found > MAX_ROWS:
        result["truncated"] = True
        result["note"] = f"Showing {MAX_ROWS} of {total_found} results. Refine the query to see more."
    return result

