import csv, io
from typing import Any

def read_csv_report(path: str, max_rows: int = 50) -> dict:
    """Return the first max_rows of a CSV as structured data."""
    try:
        with open(path, newline="", encoding="utf-8") as f:
            reader = csv.DictReader(f)
            rows: list[dict[str, Any]] = []
            total = 0
            for row in reader:
                total += 1
                if len(rows) < max_rows:
                    rows.append(dict(row))
    except FileNotFoundError:
        return {"error": "NOT_FOUND", "message": f"File not found: {path}"}
    except Exception as exc:
        return {"error": "READ_ERROR", "message": str(exc)}

    result: dict[str, Any] = {
        "path": path,
        "columns": list(rows[0].keys()) if rows else [],
        "total_rows": total,
        "returned_rows": len(rows),
        "rows": rows,
    }
    if total > max_rows:
        result["truncated"] = True
        result["note"] = f"Showing first {max_rows} of {total} rows."
    return result

def describe_pdf(path: str) -> dict:
    """Return metadata about a PDF without embedding raw bytes."""
    import os
    size = os.path.getsize(path)
    return {
        "path": path,
        "size_bytes": size,
        "message": (
            "PDF content cannot be embedded in a tool result. "
            "Use a document extraction tool to read specific pages."
        ),
    }

import anthropic

PAGE_SIZE = 10

def list_invoices(customer_id: str, cursor: str | None = None) -> dict:
    """Return a page of invoices with a cursor for the next page."""
    raw, next_cursor = _fetch_invoices(customer_id, after=cursor, limit=PAGE_SIZE)
    return {
        "customer_id": customer_id,
        "invoices": [
            {"id": inv["id"], "date": inv["date"], "amount_usd": inv["amount"],
             "status": inv["status"]}
            for inv in raw
        ],
        "has_more": next_cursor is not None,
        "next_cursor": next_cursor,
    }

def _fetch_invoices(customer_id: str, after: str | None, limit: int):
    all_inv = [{"id": f"inv_{i}", "date": "2026-07-01",
                "amount": 9.99 * i, "status": "paid"} for i in range(35)]
    start = 0
    if after:
        ids = [i["id"] for i in all_inv]
        start = ids.index(after) + 1 if after in ids else 0
    page = all_inv[start:start + limit]
    next_cursor = page[-1]["id"] if len(page) == limit and start + limit < len(all_inv) else None
    return page, next_cursor

# Agent loop that follows pagination automatically
client = anthropic.Anthropic()

tools = [{
    "name": "list_invoices",
    "description": "List invoices for a customer. Pass next_cursor from a previous result to fetch the next page.",
    "input_schema": {
        "type": "object",
        "properties": {
            "customer_id": {"type": "string"},
            "cursor": {"type": "string", "description": "Pagination cursor from a previous call"},
        },
        "required": ["customer_id"],
    },
}]

def run_invoice_agent(customer_id: str) -> str:
    messages = [{"role": "user", "content": f"List all invoices for customer {customer_id}"}]
    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=2048, tools=tools, messages=messages
        )
        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if hasattr(b, "text"))
        messages.append({"role": "assistant", "content": resp.content})
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = list_invoices(**block.input)
                results.append({"type": "tool_result", "tool_use_id": block.id,
                                 "content": str(result)})
        messages.append({"role": "user", "content": results})
